// E2e tests for category: interaction

String _alefE2eText(Object? value) {
  if (value == null) return '';
  // Check if it's an enum by examining its toString representation.
  final str = value.toString();
  if (str.contains('.')) {
    // Enum.toString() returns 'EnumName.variantName'. Extract the variant name.
    final parts = str.split('.');
    if (parts.length == 2) {
      final variantName = parts[1];
      // Convert camelCase variant names to snake_case for serde compatibility.
      // E.g. 'toolCalls' -> 'tool_calls', 'stop' -> 'stop'.
      return _camelToSnake(variantName);
    }
  }
  return str;
}

String _camelToSnake(String camel) {
  final buffer = StringBuffer();
  for (int i = 0; i < camel.length; i++) {
    final char = camel[i];
    if (char.contains(RegExp(r'[A-Z]'))) {
      if (i > 0) buffer.write('_');
      buffer.write(char.toLowerCase());
    } else {
      buffer.write(char);
    }
  }
  return buffer.toString();
}

PageAction _parsePageAction(Map<String, dynamic> json) {
  final actionType = json['type'] as String?;
  switch (actionType) {
    case 'click':
      return PageAction.click(selector: json['selector'] as String);
    case 'type':
      return PageAction.typeText(
        selector: json['selector'] as String,
        text: json['text'] as String,
      );
    case 'press':
      return PageAction.press(key: json['key'] as String);
    case 'scroll':
      return PageAction.scroll(
        direction: ScrollDirection.down,
        selector: json['selector'] as String? ?? '',
        amount: json['amount'] as int? ?? 0,
      );
    case 'wait':
      return PageAction.wait(
        milliseconds: json['timeout_ms'] as int? ?? 0,
        selector: json['selector'] as String,
      );
    case 'screenshot':
      return PageAction.screenshot(
        fullPage: json['full_page'] as bool? ?? false,
      );
    case 'executeJs':
      return PageAction.executeJs(script: json['script'] as String);
    case 'scrape':
      return const PageAction.scrape();
    default:
      throw UnsupportedError('Unknown PageAction type: $actionType');
  }
}

